import React, { useState, useEffect } from 'react';

const TABS = ['Home', 'About', 'Global Friends', 'Resources', 'Contact'];

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 60);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <nav style={{
      position: 'fixed', top: 0, left: 0, right: 0, zIndex: 1000,
      display: 'flex', alignItems: 'center', justifyContent: 'space-between',
      padding: '18px 52px',
      background: scrolled ? 'rgba(30,30,30,.88)' : 'transparent',
      backdropFilter: scrolled ? 'blur(12px)' : 'none',
      transition: 'background .35s ease, backdrop-filter .35s ease',
    }}>

      {/* Logo */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 10, cursor: 'pointer' }}>
        <div style={{
          width: 42, height: 42, borderRadius: '50%',
          background: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontWeight: 900, fontSize: 15, letterSpacing: '-0.5px',
          boxShadow: '0 2px 10px rgba(0,0,0,.15)',
        }}>
          <span style={{ color: '#fa824c' }}>G</span>
          <span style={{ color: '#2d80f2' }}>F</span>
        </div>
        <span style={{ color: 'white', fontWeight: 800, fontSize: 17, letterSpacing: '.3px' }}>
          Global Friends
        </span>
      </div>

      {/* Centered nav links */}
      <div style={{
        position: 'absolute', left: '50%', transform: 'translateX(-50%)',
        display: 'flex', gap: 34,
      }}>
        {TABS.map(tab => (
          <a key={tab} href="#" className="nav-link" style={{
            color: 'white', textDecoration: 'none',
            fontWeight: 700, fontSize: 14.5,
            opacity: tab === 'Home' ? 1 : 0.88,
          }}>
            {tab}
          </a>
        ))}
      </div>

      {/* CTA */}
      <button className="btn-orange" style={{
        background: '#fa824c', color: 'white', border: 'none',
        borderRadius: 24, padding: '10px 22px',
        fontFamily: 'Nunito, sans-serif', fontWeight: 800, fontSize: 14, cursor: 'pointer',
        boxShadow: '0 3px 12px rgba(250,130,76,.35)',
      }}>
        Join Now
      </button>
    </nav>
  );
}
